import React, { useState } from 'react';

function InicioForm({ onContinue }) {
  const [entrevistador, setEntrevistador] = useState('');
  const [postulante, setPostulante] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!entrevistador.trim() || !postulante.trim()) {
      setError('Ambos nombres son obligatorios.');
      return;
    }

    try {
      const response = await fetch('http://localhost/sistema-entrevistas/backend/api/registrar_nombres.php', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ entrevistador, postulante })
      });

      const data = await response.json();
      if (data.status === 'ok') {
        onContinue(data.entrevistador_id, data.postulante_id);
      } else {
        setError('Error al registrar los nombres.');
      }
    } catch (err) {
      setError('No se pudo conectar al backend.');
      console.error(err);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <h2>Inicio de entrevista</h2>
      <label>Nombre del entrevistador:</label>
      <input
        type="text"
        value={entrevistador}
        onChange={(e) => setEntrevistador(e.target.value)}
        style={{ display: 'block', marginBottom: '10px', padding: '8px' }}
      />

      <label>Nombre del postulante:</label>
      <input
        type="text"
        value={postulante}
        onChange={(e) => setPostulante(e.target.value)}
        style={{ display: 'block', marginBottom: '10px', padding: '8px' }}
      />

      {error && <p style={{ color: 'red' }}>{error}</p>}

      <button type="submit" style={{ padding: '10px 20px' }}>
        Comenzar entrevista
      </button>
    </form>
  );
}

export default InicioForm;
